                    elif hasattr(response, 'model_dump'):
                        return response.model_dump()
                    return response
                except Exception as e:
                    err_msg = str(e).lower()
                    if "429" in err_msg or "quota" in err_msg or "rate limit" in err_msg or "503" in err_msg:
