            if schema:
                try:
                    schema_json = schema.schema_json()
                except AttributeError:
                    schema_json = json.dumps(schema.model_json_schema())
                current_prompt += f"\n\nSCHEMA BẮT BUỘC (TUYỆT ĐỐI KHÔNG ĐỔI TÊN KEY HOẶC THIẾU KEY):\n{schema_json}"

